var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"후우...... 후우우......","JPN":"ふう……ふうう……","ENG":"*Blows on the hand* Brrr...","TWN":"呼……呼……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"또 손에 서리가 내렸네. 그거 입김 분다고 녹기는 해?","JPN":"また手が凍ってる。それ、息を吹きかけただけで治るの？","ENG":"Your hands are all frosty again. Do they get warm when you blow on them?","TWN":"妳手上又結霜了。那樣吹氣就會融化嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"이거 받아. 손난로야. 몇 번 흔들고 나면 금방 따듯해져.","JPN":"これ使いな。カイロだよ。何回か振ればすぐ温かくなるから。","ENG":"Take this. It's a handwarmer. Give it a few shakes, and it'll start getting warm.","TWN":"拿著吧，這是暖暖包，搖幾次馬上就會變暖的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아, 고마워요. 저도 준비해 둘 걸 그랬네요.","JPN":"ああ、ありがとうございます。私も用意しておくべきでしたわ。","ENG":"Ah, thank you. I should have brought some myself.","TWN":"啊，謝謝。我也應該準備一下的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하아...... 따듯해......","JPN":"はあ……温かい……","ENG":"Aaah... It's warm...","TWN":"哈啊……好暖……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"신기하네. 자기 능력 때문에 너처럼 고생하는 카운터는 처음 봤어.","JPN":"不思議だね。自分の能力のせいでアンタみたいに苦労するカウンターは初めて見たよ。","ENG":"You're weird. You're the first Counter I've ever met who has trouble with her own ability.","TWN":"真是有趣。第一次見到妳這種會因為自己的能力而吃到苦頭的制裁者。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그래도 싸움 실력은 쑥쑥 느는데? 사실 이쪽 방면으로 재능 있는 거 아냐?","JPN":"それでも戦いの腕はどんどん上がってるね。もしかして、こっち方面にも才能があるとか？","ENG":"But your combat skills are improving by the minute. Maybe you're more talented in this area than you think.","TWN":"不過感覺戰鬥實力卻不斷在成長？妳其實很有這方面的才能吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"칭찬은 됐어요. 그런 아부 듣는다고 용병이 될 생각은 없으니까요.","JPN":"褒めても無駄ですわ。そんなお世辞を言われても、傭兵になる気はありませんから。","ENG":"Save your compliments, please. They're not going to make me want to work as a mercenary.","TWN":"別誇我了，就算聽到妳拍馬屁，我也沒有當傭兵的想法。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"좋다고 실실 웃는 주제에 시치미 떼긴.","JPN":"嬉しそうにニコニコ笑ってるくせに、とぼけちゃって。","ENG":"Oh yeah? Try to say that without a smile on your face.","TWN":"妳都在吃吃竊笑了，不要裝傻。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"크흠, 흠! 웃기는 누가 웃어요!","JPN":"オッホン！　笑ってませんわ！","ENG":"W-what? I didn't smile!","TWN":"咳咳！誰笑了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그나저나 에델은 무사한가요? 침식체들이 에델 쪽으로도 달려든 것 같던데요?","JPN":"ところで、エデルは無事ですか？\\n侵食体がエデルの方に押し寄せて行ったみたいですが……","ENG":"Anyway, will Edel be all right? I saw a bunch of C.O.s running in her direction.","TWN":"不過艾瑟兒沒事吧？侵蝕體好像都往艾瑟兒的方向去了？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"에델이라면 괜찮아. 다른 아이들이 늘 지켜 주고 있거든.","JPN":"エデルなら心配いらないよ。他の子たちがいつも守ってくれるから。","ENG":"She'll be fine. Her babies will keep her safe.","TWN":"艾瑟兒不會有事的，其它孩子們一直都在保護她。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아이들?","JPN":"他の子たち？","ENG":"Babies?","TWN":"孩子？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아, 혹시 그 애완동물 말인가요?","JPN":"ああ、もしかしてペットのことですの？","ENG":"Ah, you mean the pets she's been raising at the mansion?","TWN":"啊，妳是指那些寵物嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"애완동물?","JPN":"ペット？","ENG":"Pets?","TWN":"寵物？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"뭐, 비슷하다면 비슷하지?","JPN":"まあ、ペットと言えばペットなのかな。","ENG":"I guess that's close enough of a word.","TWN":"嗯，說像是很像啦？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그리고 아니면 뭐 어때!","JPN":"ペットじゃなくても別にいいけどね！","ENG":"And who cares?","TWN":"但不是又如何！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"의뢰주 안전에 신경 꺼도 되는 의뢰라니, 정말 최고잖아!","JPN":"クライアントの安全を気にしなくていい依頼なんて、本当に最高だし！","ENG":"This is the best job ever. I don't even have to care about my client's safety!","TWN":"不用去擔心委託人的安危，這份委託真是太棒了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......다음에 용병이 필요한 일이 생겨도 당신만은 고용하면 안 된다는 건 확실히 알겠네요.","JPN":"……いつか傭兵が必要になっても、あなたを雇ってはいけないことだけは間違いありませんわね。","ENG":"One thing's clear: You'd be the last person I would consider hiring as a mercenary.","TWN":"……如果我下次需要找傭兵的話，我會記住絕對不要找妳的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그보다 나 궁금한 게 있는데 물어 봐도 돼?","JPN":"それより、気になることがあるんだけど……聞いていい？","ENG":"By the way, I've got a question for you.","TWN":"話說回來，我有件好奇的事情，可以問嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"손난로도 받았으니 질문쯤이야. 말씀해 보세요.","JPN":"カイロもいただいたので、質問くらいなら。どうぞ。","ENG":"Fine. I can answer a question or two for this handwarmer you gave me. What is it?","TWN":"我都拿了妳的暖暖包了，當然沒問題，請說吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"다들 학회장이니 뭐니 하던데, 대체 학회는 뭘 연구하는 데야?","JPN":"学会長だ何だって言ってたけど、何を研究する学会なの？","ENG":"What's this Society that everyone's talking about? What are they researching at the Society?","TWN":"大家都說什麼學會不學會的，到底學會是在研究什麼的啊？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"다른 질문을 하세요. 학회 이야기는 입에 담기도 싫습니다.","JPN":"他の質問にしてください。学会のことは口にもしたくありませんわ。","ENG":"Another question, please. I don't want to talk about anything related to that stupid Society.","TWN":"請換一個問題吧，我討厭說學會的事情。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"뭐 어때서 그래. 우리 사이에 그 정도는 말해 줘도 괜찮잖아.","JPN":"いいじゃん。アタシたちの仲なんだから、それくらい話してよ。","ENG":"Come on, it's between you and me. You can share secrets with me.","TWN":"這沒什麼吧，以我們之間的關係，這種程度的事情說說也不會怎樣嘛。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"우리 사이가 어떤 사이인데요?","JPN":"私たちの仲ってどんな仲でしたっけ？","ENG":"Huh? What's you and me?","TWN":"我們是什麼關係啊？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"달밤에 숲에서 화기애애하게 침식체 머리통을 터트리는 사이?","JPN":"月夜の森で仲良く侵食体の頭を爆発させる仲？","ENG":"We're a duo that's running around the forest at night, blowing the heads off of C.O.s.","TWN":"在深夜的森林裡，一起和樂融融地炸爛侵蝕體腦袋的關係？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하아......","JPN":"ふう……","ENG":"*Sigh*","TWN":"唉……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"알겠어요. 가르쳐 드리죠.","JPN":"分かりましたわ。お教えしましょう。","ENG":"Fine. I'll tell you.","TWN":"好啦，我就告訴妳吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"학회...... 그러니까 에크하르트 초월지식 학회는 지식의 호수에 다다르려는 곳입니다.","JPN":"学会……つまり、エクハルト超越知識学会は知識の湖を目指す組織です。","ENG":"The Society... Eckhart's\xA0Society\xA0for\xA0Preternatural\xA0Research is a group of researchers trying to find a way to reach the Lake of Knowledge.","TWN":"學會……所以說，埃克哈特超越知識學會是一個想要到達知識之湖的地方。"},"stage":{"bg":"SS_ESPR_02","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"전승에 따르면, 저희 가문의 조상이신 에크하르트 님께서 항해 중 조난 당했을 때 지식의 호수를 찾으란 계시를 받고 세웠다고 해요.","JPN":"伝承によると、マクレディー家の祖先であるエクハルト様が\\n航海中に遭難された時に、知識の湖を探せという啓示を受けて\\n創設したと言われていますの。","ENG":"According to lore, it was founded by one of my ancestors, named Eckhart, after a revelation he received while shipwrecked.","TWN":"根據傳說，我們家族的祖先埃克哈特大人在航海中遇難時，受到了要去尋找知識之湖的啟示。"},"stage":{"bg":"SS_ESPR_02","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"지식의 호수? 그건 어디 붙어 있는 호수야?","JPN":"知識の湖？　それはどこにある湖なの？","ENG":"The Lake of Knowledge? Where the heck is that?","TWN":"知識之湖？那是在哪裡的湖啊？"},"stage":{"bg":"SS_ESPR_02","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아무도 몰라요. 추상적인 표현인지, 실재하는 호수인지, 혹은 단순한 망상인지.","JPN":"それは誰も知りませんわ。抽象的な表現なのか、実在する湖なのか、もしくは単なる妄想なのか。","ENG":"No one knows. There's not a soul that knows if it's just an expression, a real lake in existence, or a total delusion.","TWN":"沒有人知道。也不知道那是抽象表現，還是某個真實存在的湖，又或者只是種妄想。"},"stage":{"bg":"SS_ESPR_02","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"게다가 더 큰 문제는 그 목적을 이루기 위한 수단이 누가 봐도 한심한 사이비 연구란 거예요.","JPN":"そして、さらに大きい問題は目的達成のための手段が誰が見ても怪しい研究ということです。","ENG":"What is worse, the way they're pursuing their goal is just plain preposterous.","TWN":"而且更大的問題是，學會為了達成這個目的所使用的手段，不管是誰看了，都會認為這是個可悲的邪教研究。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"드루이드의 주술이나 이집트의 흑마술을 배우는 것까지는 그렇다고 쳐요.","JPN":"ドルイドの呪術やエジプトの黒魔術を学ぶことはまだ許せるとして……","ENG":"As if learning druid sorcery and Egyptian black magic wasn't enough,","TWN":"他們連德魯伊的咒術和埃及的黑魔法都會去學。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"공포 소설에 나온 묘사로 호수의 위치를 역산하려는 시도는 말이 안되잖아요?!","JPN":"ホラー小説に出てくるような方法で湖の位置を逆算しようとするなんてあり得ないでしょう！？","ENG":"they're trying to locate the lake based on the description written in a horror story!","TWN":"甚至試圖以恐怖小說中出現的描寫，來逆推出湖泊的位置，這完全不像話對吧？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그런 엉터리 짓으로 무슨 학술적인 성취를 얻겠어요.","JPN":"そんな方法で学術的な成果など得られるわけがありませんわ。","ENG":"What academic achievements could they possibly make by doing that?","TWN":"做這種蠢事是能得到什麼學術成果啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"학회란 이름부터가 학문 하는 사람들에 대한 모독이에요.","JPN":"学会という名称自体が、学問の道を歩む人々への冒涜なのです。","ENG":"The fact that the organization is called Society is an insult to serious scholars.","TWN":"學會這種東西，光名字就是對學者的侮辱。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"글쎄? 난 음모론 같은 거 좋아해서 그런지 재미있게 들리는데?","JPN":"そう？　アタシは陰謀論とか好きだから、ちょっと面白そうだと思うけど？","ENG":"I don’t know. I like conspiracy theories, and it sounds very interesting to me.","TWN":"誰知道呢？也許是我蠻喜歡陰謀論的關係，聽起來還挺有意思的啊？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"잘 모르지만 트로이란 도시도 옛날옛적에 쓴 책을 연구하던 사람이 찾은 거라며?","JPN":"よく知らないけど、トロイっていう都市も昔々に書かれた本を研究してた人が見つけたんでしょ？","ENG":"I'm a layman, but wasn't the city named Troy discovered by someone who had been researching books that were written ages ago?","TWN":"雖然我不太清楚，不過聽說特洛伊這座城市也是那些研究古書的人找到的啊？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"혹시 알아? 학회가 연구하던 공포 소설이 나중에 사실이라고 밝혀질지?","JPN":"もしかしたら、そのうち学会が研究してたホラー小説が事実だって証明されたりして。","ENG":"Who knows? The horror fiction that the Society's been researching could actually prove to be based on truth.","TWN":"誰知道呢？搞不好學會研究的恐怖小說之後也會被證實吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"갖다 붙여도 정도가 있죠! 일리아드는 역사적인 사실을 기반으로 기록된 이야기라고요!","JPN":"一緒にしないでください！　イリアスは歴史的な事実を基に記録された物語ですの！","ENG":"Don't make me laugh! The Iliad was composed based on historical facts!","TWN":"亂舉例子也該有個限度吧！《伊利亞特》是以歷史事實為基礎寫成的故事！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"처음부터 사람들이 그렇게 생각하진 않았잖아.","JPN":"最初は誰もそう思わなかったはずだけど。","ENG":"But people didn't see it that way from the beginning.","TWN":"但一開始人們都不那麼認為不是嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"외눈박이 거인이나 공포 소설 속 괴물이나 내가 보기엔 그게 그건데?","JPN":"一つ目の巨人もホラー小説に出てくる怪物も似たようなものだし。","ENG":"To me, a one-eyed giant is just as unreal as a monster in a horror fiction.","TWN":"獨眼巨人也好，恐怖小說裡的怪物也好，在我看來也都差不多啊？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"궤변이에요. 그런 초자연적인 존재를 논하고 싶으면 최소한의 근거라도 가지고 와야죠.","JPN":"詭弁ですわ。\\nそんな超自然的な存在のことを語りたいなら、\\n最低限の根拠でも示してもらいたいですわね。","ENG":"It is pure sophistry. If you want to talk about supernatural beings, first you bring evidence to the table.","TWN":"妳這是詭辯。如果妳想和我討論這種超自然的存在，也該拿個最基礎的證據來吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"흐음...... 그래?","JPN":"ふうん……そう？","ENG":"Hmm... Yeah?","TWN":"哼嗯……是嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"하긴 난 예전부터 공부랑은 담 쌓고 살았으니까. 레지나 말이 맞겠지.","JPN":"まあ、アタシは昔から勉強には縁がないタイプだし。レジーナの言うとおりなんだと思うよ。","ENG":"Well, I've never considered myself a scholarly type. You're probably right.","TWN":"也是啦，畢竟我從以前開始就與念書無緣，蕾佳娜說得應該就是對的吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"바보 같은 소리해서 미안~ 가서 에델이나 데려 올게~","JPN":"バカっぽいこといってごめんね～。エデルでも迎えに行ってくるわ～。","ENG":"Heh, sorry for the ignorant remarks. I'll just go get Edel.","TWN":"抱歉啦，說了傻話～那我去把艾瑟兒帶來囉～"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"신화나 전설은 고도의 정치적 메타포를 내포하고 있습니다.","JPN":"神話や伝説は高度な政治的メタファーを内包しています。","ENG":"All the myths and legends were created with highly political metaphors.","TWN":"神話和傳說中，包含了相當高度的政治隱喻。"},"stage":{"bg":"CLASS","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"번개를 던지는 제우스라거나, 불사신 아킬레우스가 실재했다고 믿는 사람은 없죠.","JPN":"雷を投げるゼウスや、不死の神アキレスが実在したと信じる者はいないでしょう。","ENG":"No one living in the current era would believe that the lightning-wielding Zeus or the immortal Achilles existed in reality.","TWN":"像是投擲雷電的宙斯、不滅的阿克琉斯，沒有人會相信他們真正存在吧。"},"stage":{"bg":"CLASS","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"하지만 세상에 완전히 새로운 이야기는 없어요.","JPN":"ですが、この世には完全な無から作り出された物語は存在しません。","ENG":"But there's no completely new story in this world.","TWN":"然而，世界上不會有完全嶄新的故事。"},"stage":{"bg":"CLASS","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"모티브는 어디에나 존재합니다. 하늘을 향한 당대 사람들의 경외심을 제우스의 번개로 표현했듯이 말이죠.","JPN":"モチーフはどこにでも存在するのです。当時の人々の天への敬畏をゼウスの雷で表現したように。","ENG":"People see motifs everywhere, just as the ancient Greeks used their awe and fear toward the sky to create Zeus and his lightning.","TWN":"動機在哪裡都會存在，就像當代的人們把對天空的敬畏心，用宙斯的閃電來表現那樣。"},"stage":{"bg":"CLASS","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그렇다면 이런 의문을 가질 수도 있습니다.","JPN":"ならば、このような疑問を持つこともできますね。","ENG":"Then, you might wonder.","TWN":"那麼，妳接著就會產生這個疑問。"},"stage":{"bg":"CLASS","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"만에 하나, 학회에서 수집하는 조잡한 잡동사니들 사이에 진실의 편린이 섞여 있다면......","JPN":"万が一、学会が収集する粗雑ながらくたの中に真実のかけらが混ざっているとしたら……","ENG":"What if there were in fact a tiny bit of truth among the numerous useless articles that the Society has been collecting?","TWN":"萬一，在學會收集的這些亂七八糟的破爛中，夾雜著真實的一鳞半爪……"},"stage":{"bg":"SS_ESPR_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"그들은 대체 무엇을 본 것일까?","JPN":"彼らはいったい何を見たのだろうか？","ENG":"What did they see?","TWN":"那麼他們究竟看到了什麼？"},"stage":{"bg":"SS_ESPR_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"무엇을 경고하려고 했던 것일까?","JPN":"何を警告しようとしたのだろうか？","ENG":"What were they trying to warn us about?","TWN":"想要試圖警告什麼？"},"stage":{"bg":"SS_ESPR_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};